queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?documentaries a :Documentaries .
    ?documentaries p:Title ?title .
    ?documentaries p:Budget ?budget_f .
    FILTER((STR(?budget_f) = "500000" || STR(?budget_f) = "500000.0"))
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?shortfilms a :ShortFilms .
    ?shortfilms p:Title ?title .
    ?shortfilms p:Budget ?budget_f .
    FILTER((STR(?budget_f) = "500000" || STR(?budget_f) = "500000.0"))
    BIND(?title AS ?o0)
  }
}

